function solve(n: number, edges: number[][], label: string): number {
    // Build adjacency list
    const adj: number[][] = Array.from({ length: n }, () => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    // Memoization cache for visited nodes
    const memo: Map<string, number> = new Map();

    // Helper function to perform DFS and find the longest palindrome
    function dfs(node: number, visited: number[], path: string[]): number {
        // Convert visited to a string for memoization
        const key = visited.join(',');
        if (memo.has(key)) {
            return memo.get(key) as number;
        }

        // Initialize the maximum length
        let maxLen = 0;

        // Check if the current path is a palindrome
        const currentPath = path.join('');
        if (isPalindrome(currentPath)) {
            maxLen = currentPath.length;
        }

        // Try all adjacent nodes
        for (const neighbor of adj[node]) {
            if (!visited.includes(neighbor)) {
                // Mark neighbor as visited
                const newVisited = [...visited, neighbor];
                // Add the label of the neighbor to the path
                const newPath = [...path, label[neighbor]];
                // Recursively explore
                const len = dfs(neighbor, newVisited, newPath);
                maxLen = Math.max(maxLen, len);
            }
        }

        // Memoize the result
        memo.set(key, maxLen);
        return maxLen;
    }

    // Helper function to check if a string is a palindrome
    function isPalindrome(s: string): boolean {
        return s === s.split('').reverse().join('');
    }

    // Start DFS from each node
    let result = 0;
    for (let i = 0; i < n; i++) {
        const initialVisited = [i];
        const initialPath = [label[i]];
        const len = dfs(i, initialVisited, initialPath);
        result = Math.max(result, len);
    }

    return result;
}

